abstract class Shape {
    String color;

    Shape(String color) { this.color = color; }

    abstract double calculateArea();
    abstract double calculatePerimeter();

    void displayColor() { System.out.println("Color: " + color); }
}

class Circle extends Shape {
    double radius;

    Circle(String color, double radius) {
        super(color);
        this.radius = radius;
    }

    @Override double calculateArea() { return Math.PI * radius * radius; }
    @Override double calculatePerimeter() { return 2 * Math.PI * radius; }
}

public class AbstractClassDemo {
    public static void main(String[] args) {
        Circle c = new Circle("Red", 5);
        c.displayColor();
        System.out.printf("Area: %.2f%n", c.calculateArea());
    }
}

