interface Drawable {
    void draw();
}

interface Resizable {
    void resize(double factor);
}

class GraphicCircle implements Drawable, Resizable {
    double radius;
    String color;

    GraphicCircle(String color, double radius) {
        this.color = color;
        this.radius = radius;
    }

    public void draw() {
        System.out.printf("Drawing %s circle, radius %.1f%n", color, radius);
    }

    public void resize(double factor) {
        radius *= factor;
        System.out.println("Resized. New radius: " + radius);
    }
}

public class InterfaceDemo {
    public static void main(String[] args) {
        Drawable d = new GraphicCircle("Blue", 10);
        d.draw();
        ((Resizable) d).resize(1.5);
        d.draw();
    }
}

