import java.util.Scanner;

class Book {
    String title, author, isbn;
    boolean isAvailable = true;

    Book(String title, String author, String isbn) {
        this.title = title; this.author = author; this.isbn = isbn;
    }

    void display() {
        System.out.printf("[%s] %s by %s - %s%n", isbn, title, author,
                isAvailable ? "Available" : "Issued");
    }
}

public class LibraryManagementSystem {
    static Book[] books = new Book[200];
    static int count = 0;
    static Scanner sc = new Scanner(System.in);

    static void addBook() {
        sc.nextLine();
        System.out.print("Title: "); String t = sc.nextLine();
        System.out.print("Author: "); String a = sc.nextLine();
        System.out.print("ISBN: "); String isbn = sc.nextLine();
        books[count++] = new Book(t, a, isbn);
        System.out.println("Book added.");
    }

    static void displayAll() {
        for (int i = 0; i < count; i++) books[i].display();
    }

    public static void main(String[] args) {
        books[count++] = new Book("Effective Java", "Joshua Bloch", "ISBN-001");
        displayAll();
        sc.close();
    }
}

