public class BankManagementSystem {
    static BankAccount[] accounts = new BankAccount[100];
    static int count = 0;

    static BankAccount findAccount(String num) {
        for (int i = 0; i < count; i++) {
            if (accounts[i].accountNumber.equals(num)) return accounts[i];
        }
        return null;
    }

    static void transfer(String from, String to, double amount) {
        BankAccount src = findAccount(from);
        BankAccount dst = findAccount(to);
        if (src == null || dst == null) {
            System.out.println("Account not found."); return;
        }
        if (amount > src.getBalance()) {
            System.out.println("Insufficient funds for transfer."); return;
        }
        src.withdraw(amount);
        dst.deposit(amount);
        System.out.println("Transfer successful.");
    }

    public static void main(String[] args) {
        accounts[count++] = new BankAccount("A001", "Riya", 10000);
        accounts[count++] = new BankAccount("A002", "Amit", 5000);
        transfer("A001", "A002", 3000);
        accounts[0].displayAccount();
        accounts[1].displayAccount();
    }
}

